# -*- coding: utf-8 -*- from __future__ import annotations  import ctypes import json import os import queue import re import subprocess import sys import threading import webbrowser from dataclasses import dataclass from datetime import date, datetime, timedelta from pathlib import Path import tkinter as tk from tkinter import filedialog, font as tkfont, messagebox, ttk   APP_NAME = "Dake工程カレンダー" WINDOW_TITLE = "工程カレンダー" COPYRIGHT = "© 2026 しまりす不動産 — Vibe-Coded by Yukihiko Kikuta"  CONFIG_NAME = "dake_work_calendar_config.json" COMMON_ICON_RELATIVE = Path("..") / ".." / "02_assets" / "dake_icon.ico" COMMON_ICON_FILENAME = "dake_icon.ico"  UI_TEXT = {     "display_name": "工程カレンダー",     "main_heading": "工程カレンダー",     "main_subtitle": "現場名・期間・工程を入力して、A4横の工程カレンダーPDFを作成します。",     "section_site": "現場情報",     "section_period": "期間と保存先",     "section_events": "工程入力",     "label_site_name": "現場名",     "label_branch_name": "支店名",     "label_staff_name": "担当者名",     "label_phone": "電話番号",     "label_start_date": "開始日",     "label_end_date": "終了日",     "label_save_folder": "保存先",     "label_event_date": "日付",     "label_event_content": "内容",     "date_hint": "例：2025/11/29",     "button_browse": "選択",     "button_create_pdf": "PDF作成",     "status_ready": "入力してPDF作成を押してください。",     "status_processing": "PDFを作成しています...",     "status_saved": "PDFを保存しました。",     "status_error": "PDF作成に失敗しました。",     "dialog_select_save_dir": "保存先フォルダを選択",     "dialog_error_title": "入力エラー",     "dialog_saved_title": "保存完了",     "dialog_saved_message": "工程カレンダーPDFを保存しました。\n\n{path}",     "error_start_date": "開始日を正しく入力してください。",     "error_end_date": "終了日を正しく入力してください。",     "error_date_order": "終了日は開始日以降の日付にしてください。",     "error_event_date": "工程「{content}」の日付を正しく入力してください。",     "error_event_range": "工程「{content}」の日付は開始日〜終了日の範囲内で入力してください。",     "error_save_folder": "保存先フォルダを選択してください。",     "error_reportlab_missing": "PDF生成に必要な reportlab が見つかりません。reportlab をインストールしてください。",     "footer_series": "シンプルそれDAKEシリーズ",     "footer_estimate": "戸建買取査定",     "footer_instagram": "Instagram",     "footer_separator": " ｜ ",     "footer_copyright": COPYRIGHT,     "event_items": [         {"key": "handover", "label": "引渡し日"},         {"key": "water_removal", "label": "水道設備の撤去"},         {"key": "kitchen", "label": "キッチン設置"},         {"key": "unit_bath", "label": "ユニットバス設置"},         {"key": "carpenter", "label": "大工工事"},         {"key": "wallpaper", "label": "クロス工事"},         {"key": "cleaning", "label": "ハウスクリーニング"},         {"key": "completion", "label": "完工"},     ],     "pdf_site_placeholder": "現場名未入力",     "pdf_title_template": "{site} 工程カレンダー",     "pdf_target_period": "対象期間",     "pdf_target_month": "対象年月",     "pdf_page_range": "表示範囲",     "pdf_staff": "担当",     "pdf_day_names": ["日", "月", "火", "水", "木", "金", "土"],     "pdf_event_prefix": "・",     "pdf_completion_comment": "完工は、{date}です。\nいつもありがとうございます。引き続きよろしくお願いします！",     "pdf_contact_template": "さくら都市{branch} 担当：{staff} {phone}",     "pdf_page_suffix": "{current}/{total}ページ",     "holiday_names": {         "new_year": "元日",         "coming_age": "成人の日",         "foundation": "建国記念の日",         "emperor": "天皇誕生日",         "vernal": "春分の日",         "showa": "昭和の日",         "greenery": "みどりの日",         "constitution": "憲法記念日",         "children": "こどもの日",         "marine": "海の日",         "mountain": "山の日",         "respect": "敬老の日",         "autumnal": "秋分の日",         "sports": "スポーツの日",         "health_sports": "体育の日",         "culture": "文化の日",         "labor": "勤労感謝の日",         "citizens": "国民の休日",         "substitute": "振替休日",     }, }  LINK_TARGETS = {     "estimate": "https://sakurayk.notion.site/22ea54b5298d80928443ec7b4d20143d?pvs=74",     "instagram": "https://www.instagram.com/kikuta.shimarisu_fudosan", }  COLORS = {     "background": "#F6F7F9",     "panel": "#FFFFFF",     "text": "#1E2430",     "muted": "#667085",     "border": "#E6EAF0",     "accent": "#2F6FED",     "accent_hover": "#2458BF",     "accent_disabled": "#A8B8D8",     "entry": "#FFFFFF",     "footer": "#8A94A6",     "error": "#D92D20", }  PDF_COLORS = {     "text": "#1E2430",     "muted": "#8A94A6",     "border": "#CDD5DF",     "header_bg": "#EEF4FF",     "subtle_bg": "#F8FAFC",     "sunday_bg": "#FFF5F5",     "saturday_bg": "#F4F8FF",     "holiday": "#C43B3B",     "saturday": "#2559A8",     "accent": "#2F6FED", }  FONT_CANDIDATES = ("BIZ UDPGothic", "Yu Gothic UI", "Meiryo") DATE_FORMATS = ("%Y/%m/%d", "%Y-%m-%d", "%Y.%m.%d", "%Y%m%d") MAX_WEEKS_PER_PAGE = 6   @dataclass(frozen=True) class CalendarEvent:     key: str     event_date: date     content: str   @dataclass(frozen=True) class PdfRequest:     site_name: str     branch_name: str     staff_name: str     phone: str     start_date: date     end_date: date     save_folder: str     events: tuple[CalendarEvent, ...]     completion_date: date | None   def app_dir() -> Path:     if getattr(sys, "frozen", False):         return Path(sys.executable).resolve().parent     return Path(__file__).resolve().parent   def config_path() -> Path:     return app_dir() / CONFIG_NAME   def default_save_folder() -> str:     downloads = Path.home() / "Downloads"     if downloads.exists():         return str(downloads)     return str(Path.home())   def load_config() -> dict:     try:         with config_path().open("r", encoding="utf-8") as f:             data = json.load(f)         if isinstance(data, dict):             return data     except Exception:         pass     return {}   def save_config(data: dict) -> None:     try:         with config_path().open("w", encoding="utf-8") as f:             json.dump(data, f, ensure_ascii=False, indent=2)     except Exception:         pass   def find_icon_path() -> Path | None:     base = app_dir()     candidates = [         base / COMMON_ICON_RELATIVE,         base / ".." / ".." / ".." / "02_assets" / COMMON_ICON_FILENAME,         Path(__file__).resolve().parent / COMMON_ICON_RELATIVE,     ]     if getattr(sys, "frozen", False):         candidates.append(Path(getattr(sys, "_MEIPASS", base)) / COMMON_ICON_FILENAME)     for candidate in candidates:         resolved = candidate.resolve()         if resolved.exists():             return resolved     return None   def apply_window_icon(window: tk.Tk) -> None:     icon = find_icon_path()     if icon is None:         return     try:         window.iconbitmap(default=str(icon))     except tk.TclError:         try:             window.iconbitmap(str(icon))         except tk.TclError:             pass   def set_windows_app_id() -> None:     if not sys.platform.startswith("win"):         return     try:         ctypes.windll.shell32.SetCurrentProcessExplicitAppUserModelID("Shimarisu.DakeWorkCalendar")     except Exception:         pass   def open_folder(path: str) -> None:     try:         if sys.platform.startswith("win"):             os.startfile(path)  # type: ignore[attr-defined]         elif sys.platform == "darwin":             subprocess.Popen(["open", path])         else:             subprocess.Popen(["xdg-open", path])     except Exception:         pass   def parse_date_text(value: str) -> date | None:     text = value.strip()     if not text:         return None     for fmt in DATE_FORMATS:         try:             return datetime.strptime(text, fmt).date()         except ValueError:             continue     match = re.fullmatch(r"(\d{4})[/-](\d{1,2})[/-](\d{1,2})", text)     if match:         try:             return date(int(match.group(1)), int(match.group(2)), int(match.group(3)))         except ValueError:             return None     return None   def format_date_jp(value: date) -> str:     return f"{value.year}年{value.month}月{value.day}日"   def format_month_range(start: date, end: date) -> str:     if start.year == end.year and start.month == end.month:         return f"{start.year}年{start.month}月"     return f"{start.year}年{start.month}月〜{end.year}年{end.month}月"   def sanitize_filename(value: str) -> str:     cleaned = re.sub(r'[\\/:*?"<>|]+', "_", value).strip()     cleaned = re.sub(r"\s+", "_", cleaned)     return cleaned[:60]   def color_hex(hex_value: str):     from reportlab.lib import colors      return colors.HexColor(hex_value)   def sunday_on_or_before(value: date) -> date:     return value - timedelta(days=(value.weekday() + 1) % 7)   def saturday_on_or_after(value: date) -> date:     return value + timedelta(days=(5 - value.weekday()) % 7)   def iter_calendar_weeks(start: date, end: date) -> list[list[date]]:     first_day = sunday_on_or_before(start)     last_day = saturday_on_or_after(end)     weeks: list[list[date]] = []     current = first_day     while current <= last_day:         weeks.append([current + timedelta(days=i) for i in range(7)])         current += timedelta(days=7)     return weeks   def nth_monday(year: int, month: int, nth: int) -> date:     current = date(year, month, 1)     days_until_monday = (0 - current.weekday()) % 7     return current + timedelta(days=days_until_monday + 7 * (nth - 1))   def spring_equinox_day(year: int) -> int:     return int(20.8431 + 0.242194 * (year - 1980) - ((year - 1980) // 4))   def autumn_equinox_day(year: int) -> int:     return int(23.2488 + 0.242194 * (year - 1980) - ((year - 1980) // 4))   def fallback_japanese_holidays(years: set[int]) -> dict[date, str]:     names = UI_TEXT["holiday_names"]     holidays: dict[date, str] = {}      for year in years:         base: dict[date, str] = {}         base[date(year, 1, 1)] = names["new_year"]         base[nth_monday(year, 1, 2)] = names["coming_age"]         base[date(year, 2, 11)] = names["foundation"]          if year >= 2020:             base[date(year, 2, 23)] = names["emperor"]         elif 1989 <= year <= 2018:             base[date(year, 12, 23)] = names["emperor"]          base[date(year, 3, spring_equinox_day(year))] = names["vernal"]          if year >= 2007:             base[date(year, 4, 29)] = names["showa"]             base[date(year, 5, 4)] = names["greenery"]         elif 1989 <= year <= 2006:             base[date(year, 4, 29)] = names["greenery"]          base[date(year, 5, 3)] = names["constitution"]         base[date(year, 5, 5)] = names["children"]          if year == 2020:             base[date(year, 7, 23)] = names["marine"]             base[date(year, 7, 24)] = names["sports"]             base[date(year, 8, 10)] = names["mountain"]         elif year == 2021:             base[date(year, 7, 22)] = names["marine"]             base[date(year, 7, 23)] = names["sports"]             base[date(year, 8, 8)] = names["mountain"]         else:             if year >= 2003:                 base[nth_monday(year, 7, 3)] = names["marine"]             elif year >= 1996:                 base[date(year, 7, 20)] = names["marine"]             if year >= 2016:                 base[date(year, 8, 11)] = names["mountain"]             if year >= 2020:                 base[nth_monday(year, 10, 2)] = names["sports"]             elif year >= 2000:                 base[nth_monday(year, 10, 2)] = names["health_sports"]             else:                 base[date(year, 10, 10)] = names["health_sports"]          if year >= 2003:             base[nth_monday(year, 9, 3)] = names["respect"]         else:             base[date(year, 9, 15)] = names["respect"]          base[date(year, 9, autumn_equinox_day(year))] = names["autumnal"]         base[date(year, 11, 3)] = names["culture"]         base[date(year, 11, 23)] = names["labor"]          year_holidays = dict(base)         current = date(year, 1, 2)         while current <= date(year, 12, 30):             if current not in year_holidays:                 if current - timedelta(days=1) in year_holidays and current + timedelta(days=1) in year_holidays:                     year_holidays[current] = names["citizens"]             current += timedelta(days=1)          for holiday_date in sorted(base):             if holiday_date.weekday() == 6:                 substitute = holiday_date + timedelta(days=1)                 while substitute in year_holidays:                     substitute += timedelta(days=1)                 if substitute.year == year:                     year_holidays[substitute] = names["substitute"]          holidays.update(year_holidays)      return holidays   def japanese_holidays(years: set[int]) -> dict[date, str]:     try:         import holidays as holidays_lib  # type: ignore          try:             holiday_map = holidays_lib.country_holidays("JP", years=sorted(years), language="ja")         except TypeError:             holiday_map = holidays_lib.country_holidays("JP", years=sorted(years))         return {holiday_date: str(name) for holiday_date, name in holiday_map.items()}     except Exception:         return fallback_japanese_holidays(years)   def register_pdf_fonts() -> tuple[str, str]:     from reportlab.pdfbase import pdfmetrics     from reportlab.pdfbase.cidfonts import UnicodeCIDFont      regular = "HeiseiKakuGo-W5"     serif = "HeiseiMin-W3"     for font_name in (regular, serif):         try:             pdfmetrics.registerFont(UnicodeCIDFont(font_name))         except Exception:             pass     return regular, serif   def wrap_text_to_width(text: str, font_name: str, font_size: float, max_width: float) -> list[str]:     from reportlab.pdfbase import pdfmetrics      lines: list[str] = []     paragraphs = text.splitlines() or [""]     for paragraph in paragraphs:         current = ""         for char in paragraph:             candidate = current + char             if pdfmetrics.stringWidth(candidate, font_name, font_size) <= max_width:                 current = candidate             else:                 if current:                     lines.append(current)                 current = char         lines.append(current)     return lines   def draw_wrapped_text(     canvas,     text: str,     x: float,     y: float,     max_width: float,     font_name: str,     font_size: float,     leading: float,     max_lines: int | None = None,     fill: str = PDF_COLORS["text"], ) -> float:     lines = wrap_text_to_width(text, font_name, font_size, max_width)     if max_lines is not None and len(lines) > max_lines:         lines = lines[:max_lines]         if lines:             lines[-1] = lines[-1].rstrip(" .") + "..."     canvas.setFont(font_name, font_size)     canvas.setFillColor(color_hex(fill))     current_y = y     for line in lines:         canvas.drawString(x, current_y, line)         current_y -= leading     return current_y   def make_output_path(request: PdfRequest) -> Path:     folder = Path(request.save_folder)     folder.mkdir(parents=True, exist_ok=True)     site_part = sanitize_filename(request.site_name) or sanitize_filename(UI_TEXT["display_name"])     span = f"{request.start_date:%Y%m%d}-{request.end_date:%Y%m%d}"     output = folder / f"{UI_TEXT['display_name']}_{site_part}_{span}.pdf"     if not output.exists():         return output     suffix = datetime.now().strftime("%H%M%S")     return folder / f"{UI_TEXT['display_name']}_{site_part}_{span}_{suffix}.pdf"   def generate_pdf(request: PdfRequest) -> Path:     try:         from reportlab.lib.pagesizes import A4, landscape         from reportlab.pdfbase import pdfmetrics         from reportlab.pdfgen import canvas     except Exception as exc:         raise RuntimeError(UI_TEXT["error_reportlab_missing"]) from exc      output_path = make_output_path(request)     page_width, page_height = landscape(A4)     pdf = canvas.Canvas(str(output_path), pagesize=(page_width, page_height))     font_name, serif_font = register_pdf_fonts()      weeks = iter_calendar_weeks(request.start_date, request.end_date)     chunks = [weeks[i : i + MAX_WEEKS_PER_PAGE] for i in range(0, len(weeks), MAX_WEEKS_PER_PAGE)]     events_by_date: dict[date, list[CalendarEvent]] = {}     for event in request.events:         events_by_date.setdefault(event.event_date, []).append(event)      all_years: set[int] = set()     for week in weeks:         for day in week:             all_years.add(day.year)     holiday_map = japanese_holidays(all_years)      margin_x = 28     header_y = page_height - 34     calendar_top = page_height - 120     day_header_h = 22     grid_bottom = 118     calendar_width = page_width - margin_x * 2     cell_w = calendar_width / 7      site = request.site_name.strip() or UI_TEXT["pdf_site_placeholder"]     title = UI_TEXT["pdf_title_template"].format(site=site)     period_text = f"{format_date_jp(request.start_date)}〜{format_date_jp(request.end_date)}"     month_text = format_month_range(request.start_date, request.end_date)     contact_text = UI_TEXT["pdf_contact_template"].format(         branch=request.branch_name.strip(),         staff=request.staff_name.strip(),         phone=request.phone.strip(),     ).strip()      for page_index, chunk in enumerate(chunks, start=1):         row_count = len(chunk)         grid_top = calendar_top - day_header_h         row_h = (grid_top - grid_bottom) / row_count          pdf.setFillColor(color_hex(PDF_COLORS["text"]))         pdf.setFont(font_name, 18)         pdf.drawString(margin_x, header_y, title)          page_suffix = UI_TEXT["pdf_page_suffix"].format(current=page_index, total=len(chunks))         pdf.setFont(font_name, 8.8)         pdf.setFillColor(color_hex(PDF_COLORS["muted"]))         pdf.drawRightString(page_width - margin_x, header_y + 2, page_suffix)          info_y = header_y - 22         pdf.setFont(font_name, 9.2)         pdf.setFillColor(color_hex(PDF_COLORS["text"]))         pdf.drawString(margin_x, info_y, f"{UI_TEXT['pdf_target_period']}：{period_text}")         pdf.drawString(margin_x + 270, info_y, f"{UI_TEXT['pdf_target_month']}：{month_text}")         pdf.drawRightString(page_width - margin_x, info_y, f"{UI_TEXT['pdf_staff']}：{request.staff_name.strip()}")          range_start = chunk[0][0]         range_end = chunk[-1][-1]         pdf.setFont(font_name, 8.4)         pdf.setFillColor(color_hex(PDF_COLORS["muted"]))         pdf.drawString(             margin_x,             info_y - 16,             f"{UI_TEXT['pdf_page_range']}：{format_date_jp(range_start)}〜{format_date_jp(range_end)}",         )          for col, day_name in enumerate(UI_TEXT["pdf_day_names"]):             x = margin_x + col * cell_w             y = calendar_top - day_header_h             pdf.setFillColor(color_hex(PDF_COLORS["header_bg"]))             pdf.rect(x, y, cell_w, day_header_h, stroke=0, fill=1)             pdf.setStrokeColor(color_hex(PDF_COLORS["border"]))             pdf.rect(x, y, cell_w, day_header_h, stroke=1, fill=0)             if col == 0:                 pdf.setFillColor(color_hex(PDF_COLORS["holiday"]))             elif col == 6:                 pdf.setFillColor(color_hex(PDF_COLORS["saturday"]))             else:                 pdf.setFillColor(color_hex(PDF_COLORS["text"]))             pdf.setFont(font_name, 9.5)             pdf.drawCentredString(x + cell_w / 2, y + 7, day_name)          for row, week in enumerate(chunk):             for col, day in enumerate(week):                 x = margin_x + col * cell_w                 y = grid_top - (row + 1) * row_h                 in_range = request.start_date <= day <= request.end_date                 holiday_name = holiday_map.get(day)                  if not in_range:                     fill = PDF_COLORS["subtle_bg"]                 elif holiday_name or col == 0:                     fill = PDF_COLORS["sunday_bg"]                 elif col == 6:                     fill = PDF_COLORS["saturday_bg"]                 else:                     fill = "#FFFFFF"                  pdf.setFillColor(color_hex(fill))                 pdf.rect(x, y, cell_w, row_h, stroke=0, fill=1)                 pdf.setStrokeColor(color_hex(PDF_COLORS["border"]))                 pdf.rect(x, y, cell_w, row_h, stroke=1, fill=0)                  if not in_range:                     date_color = PDF_COLORS["muted"]                 elif holiday_name or col == 0:                     date_color = PDF_COLORS["holiday"]                 elif col == 6:                     date_color = PDF_COLORS["saturday"]                 else:                     date_color = PDF_COLORS["text"]                  date_label = str(day.day)                 if day.day == 1 or (row == 0 and col == 0):                     date_label = f"{day.month}/{day.day}"                 pdf.setFont(font_name, 9.5)                 pdf.setFillColor(color_hex(date_color))                 pdf.drawString(x + 6, y + row_h - 13, date_label)                  text_y = y + row_h - 25                 if holiday_name:                     pdf.setFont(font_name, 6.8)                     pdf.setFillColor(color_hex(PDF_COLORS["holiday"]))                     holiday_lines = wrap_text_to_width(holiday_name, font_name, 6.8, cell_w - 12)                     for line in holiday_lines[:2]:                         pdf.drawString(x + 6, text_y, line)                         text_y -= 8                  day_events = events_by_date.get(day, [])                 if day_events:                     max_lines = max(1, int((text_y - y - 5) // 8))                     event_font_size = 8.4                     event_leading = 9.2                     event_lines: list[str] = []                     for font_size in (8.4, 7.5, 6.7, 6.1):                         event_lines = []                         for event in day_events:                             label = UI_TEXT["pdf_event_prefix"] + event.content                             event_lines.extend(wrap_text_to_width(label, font_name, font_size, cell_w - 12))                         if len(event_lines) <= max_lines or font_size <= 6.1:                             event_font_size = font_size                             event_leading = font_size + 1.2                             break                      if len(event_lines) > max_lines:                         event_lines = event_lines[:max_lines]                         event_lines[-1] = event_lines[-1].rstrip(" .") + "..."                      pdf.setFont(font_name, event_font_size)                     pdf.setFillColor(color_hex(PDF_COLORS["text"] if in_range else PDF_COLORS["muted"]))                     current_y = text_y                     for line in event_lines:                         if current_y < y + 6:                             break                         pdf.drawString(x + 6, current_y, line)                         current_y -= event_leading          comment_y = 90         if request.completion_date is not None:             comment_text = UI_TEXT["pdf_completion_comment"].format(date=format_date_jp(request.completion_date))             draw_wrapped_text(pdf, comment_text, margin_x, comment_y, 500, serif_font, 10.2, 13)          pdf.setStrokeColor(color_hex(PDF_COLORS["border"]))         pdf.line(margin_x, 58, page_width - margin_x, 58)         pdf.setFont(font_name, 10.2)         pdf.setFillColor(color_hex(PDF_COLORS["text"]))         pdf.drawRightString(page_width - margin_x, 39, contact_text)         pdf.setFont(font_name, 7.6)         pdf.setFillColor(color_hex(PDF_COLORS["muted"]))         pdf.drawString(margin_x, 39, UI_TEXT["footer_series"])         pdf.showPage()      pdf.save()     return output_path   class WorkCalendarApp:     def __init__(self, root: tk.Tk) -> None:         self.root = root         self.root.title(WINDOW_TITLE)         self.root.configure(bg=COLORS["background"])         self.root.minsize(980, 740)         apply_window_icon(self.root)          self.config_data = load_config()         today = date.today()         self.site_name_var = tk.StringVar()         self.branch_name_var = tk.StringVar(value=self.config_data.get("branch_name", ""))         self.staff_name_var = tk.StringVar(value=self.config_data.get("staff_name", ""))         self.phone_var = tk.StringVar(value=self.config_data.get("phone", ""))         self.start_date_var = tk.StringVar(value=today.strftime("%Y/%m/%d"))         self.end_date_var = tk.StringVar(value=(today + timedelta(days=30)).strftime("%Y/%m/%d"))         self.save_folder_var = tk.StringVar(value=self.config_data.get("save_folder", default_save_folder()))         self.status_var = tk.StringVar(value=UI_TEXT["status_ready"])          self.font_family = self.choose_font_family()         self.fonts = {             "title": (self.font_family, 22, "bold"),             "subtitle": (self.font_family, 10),             "section": (self.font_family, 12, "bold"),             "body": (self.font_family, 10),             "small": (self.font_family, 9),             "button": (self.font_family, 10, "bold"),             "footer": (self.font_family, 8),         }          self.event_rows: list[dict[str, object]] = []         self.result_queue: queue.Queue[tuple[str, object]] = queue.Queue()         self.is_processing = False          self.build_ui()      def choose_font_family(self) -> str:         available = set(tkfont.families(self.root))         for candidate in FONT_CANDIDATES:             if candidate in available:                 return candidate         return "TkDefaultFont"      def build_ui(self) -> None:         outer = tk.Frame(self.root, bg=COLORS["background"])         outer.pack(fill="both", expand=True, padx=22, pady=(18, 0))          canvas = tk.Canvas(outer, bg=COLORS["background"], highlightthickness=0)         scrollbar = ttk.Scrollbar(outer, orient="vertical", command=canvas.yview)         self.content = tk.Frame(canvas, bg=COLORS["background"])         window_id = canvas.create_window((0, 0), window=self.content, anchor="nw")          def update_scrollregion(_event=None) -> None:             canvas.configure(scrollregion=canvas.bbox("all"))          def update_width(event) -> None:             canvas.itemconfigure(window_id, width=event.width)          self.content.bind("<Configure>", update_scrollregion)         canvas.bind("<Configure>", update_width)         canvas.configure(yscrollcommand=scrollbar.set)         canvas.pack(side="left", fill="both", expand=True)         scrollbar.pack(side="right", fill="y")          self.build_header()         self.build_input_sections()         self.build_actions()         self.build_footer()      def build_header(self) -> None:         header = tk.Frame(self.content, bg=COLORS["background"])         header.pack(fill="x", pady=(0, 14))         tk.Label(             header,             text=UI_TEXT["main_heading"],             font=self.fonts["title"],             fg=COLORS["text"],             bg=COLORS["background"],             anchor="w",         ).pack(anchor="w")         tk.Label(             header,             text=UI_TEXT["main_subtitle"],             font=self.fonts["subtitle"],             fg=COLORS["muted"],             bg=COLORS["background"],             anchor="w",         ).pack(anchor="w", pady=(5, 0))      def panel(self, parent: tk.Misc, title: str) -> tk.Frame:         wrapper = tk.Frame(             parent,             bg=COLORS["panel"],             highlightthickness=1,             highlightbackground=COLORS["border"],             highlightcolor=COLORS["border"],         )         wrapper.pack(fill="x", pady=(0, 12))         tk.Label(             wrapper,             text=title,             font=self.fonts["section"],             fg=COLORS["text"],             bg=COLORS["panel"],             anchor="w",         ).pack(fill="x", padx=18, pady=(14, 8))         body = tk.Frame(wrapper, bg=COLORS["panel"])         body.pack(fill="x", padx=18, pady=(0, 16))         return body      def build_input_sections(self) -> None:         site_panel = self.panel(self.content, UI_TEXT["section_site"])         for col in range(4):             site_panel.columnconfigure(col, weight=1 if col in (1, 3) else 0)         self.add_labeled_entry(site_panel, 0, 0, UI_TEXT["label_site_name"], self.site_name_var)         self.add_labeled_entry(site_panel, 0, 2, UI_TEXT["label_branch_name"], self.branch_name_var)         self.add_labeled_entry(site_panel, 1, 0, UI_TEXT["label_staff_name"], self.staff_name_var)         self.add_labeled_entry(site_panel, 1, 2, UI_TEXT["label_phone"], self.phone_var)          period_panel = self.panel(self.content, UI_TEXT["section_period"])         for col in range(5):             period_panel.columnconfigure(col, weight=1 if col in (1, 3) else 0)         self.add_labeled_entry(period_panel, 0, 0, UI_TEXT["label_start_date"], self.start_date_var)         self.add_labeled_entry(period_panel, 0, 2, UI_TEXT["label_end_date"], self.end_date_var)         tk.Label(             period_panel,             text=UI_TEXT["date_hint"],             font=self.fonts["small"],             fg=COLORS["muted"],             bg=COLORS["panel"],             anchor="w",         ).grid(row=1, column=1, columnspan=3, sticky="w", pady=(2, 8))          tk.Label(             period_panel,             text=UI_TEXT["label_save_folder"],             font=self.fonts["body"],             fg=COLORS["text"],             bg=COLORS["panel"],             anchor="w",         ).grid(row=2, column=0, sticky="w", padx=(0, 8), pady=6)         save_entry = tk.Entry(             period_panel,             textvariable=self.save_folder_var,             font=self.fonts["body"],             fg=COLORS["text"],             bg=COLORS["entry"],             relief="solid",             bd=1,         )         save_entry.grid(row=2, column=1, columnspan=3, sticky="ew", pady=6)         self.make_button(period_panel, UI_TEXT["button_browse"], self.choose_save_folder, compact=True).grid(             row=2,             column=4,             sticky="e",             padx=(10, 0),             pady=6,         )          event_panel = self.panel(self.content, UI_TEXT["section_events"])         event_panel.columnconfigure(0, weight=0)         event_panel.columnconfigure(1, weight=0)         event_panel.columnconfigure(2, weight=1)         tk.Label(             event_panel,             text=UI_TEXT["label_event_date"],             font=self.fonts["small"],             fg=COLORS["muted"],             bg=COLORS["panel"],         ).grid(row=0, column=1, sticky="w", padx=(10, 8), pady=(0, 4))         tk.Label(             event_panel,             text=UI_TEXT["label_event_content"],             font=self.fonts["small"],             fg=COLORS["muted"],             bg=COLORS["panel"],         ).grid(row=0, column=2, sticky="w", padx=(8, 0), pady=(0, 4))          for index, item in enumerate(UI_TEXT["event_items"], start=1):             label_text = str(item["label"])             date_var = tk.StringVar()             content_var = tk.StringVar(value=label_text)             tk.Label(                 event_panel,                 text=label_text,                 font=self.fonts["body"],                 fg=COLORS["text"],                 bg=COLORS["panel"],                 anchor="w",                 width=18,             ).grid(row=index, column=0, sticky="w", pady=4)             tk.Entry(                 event_panel,                 textvariable=date_var,                 font=self.fonts["body"],                 fg=COLORS["text"],                 bg=COLORS["entry"],                 relief="solid",                 bd=1,                 width=14,             ).grid(row=index, column=1, sticky="w", padx=(10, 8), pady=4)             tk.Entry(                 event_panel,                 textvariable=content_var,                 font=self.fonts["body"],                 fg=COLORS["text"],                 bg=COLORS["entry"],                 relief="solid",                 bd=1,             ).grid(row=index, column=2, sticky="ew", padx=(8, 0), pady=4)             self.event_rows.append({"key": item["key"], "date_var": date_var, "content_var": content_var})      def build_actions(self) -> None:         action_panel = tk.Frame(self.content, bg=COLORS["background"])         action_panel.pack(fill="x", pady=(2, 18))         self.progress = ttk.Progressbar(action_panel, mode="indeterminate", length=220)         self.progress.pack(side="left", padx=(0, 12))         tk.Label(             action_panel,             textvariable=self.status_var,             font=self.fonts["body"],             fg=COLORS["muted"],             bg=COLORS["background"],         ).pack(side="left")         self.create_button = self.make_button(action_panel, UI_TEXT["button_create_pdf"], self.on_create_pdf)         self.create_button.pack(side="right")      def build_footer(self) -> None:         footer = tk.Frame(self.root, bg=COLORS["background"])         footer.pack(fill="x", padx=22, pady=(8, 12))         tk.Label(             footer,             text=UI_TEXT["footer_series"],             font=self.fonts["footer"],             fg=COLORS["footer"],             bg=COLORS["background"],         ).pack(side="left")         right = tk.Frame(footer, bg=COLORS["background"])         right.pack(side="right")         self.link_label(right, UI_TEXT["footer_estimate"], LINK_TARGETS["estimate"]).pack(side="left")         tk.Label(             right,             text=UI_TEXT["footer_separator"],             font=self.fonts["footer"],             fg=COLORS["footer"],             bg=COLORS["background"],         ).pack(side="left")         self.link_label(right, UI_TEXT["footer_instagram"], LINK_TARGETS["instagram"]).pack(side="left")         tk.Label(             right,             text=UI_TEXT["footer_separator"] + UI_TEXT["footer_copyright"],             font=self.fonts["footer"],             fg=COLORS["footer"],             bg=COLORS["background"],         ).pack(side="left")      def add_labeled_entry(         self,         parent: tk.Misc,         row: int,         column: int,         label: str,         variable: tk.StringVar,     ) -> None:         tk.Label(             parent,             text=label,             font=self.fonts["body"],             fg=COLORS["text"],             bg=COLORS["panel"],             anchor="w",         ).grid(row=row, column=column, sticky="w", padx=(0, 8), pady=6)         tk.Entry(             parent,             textvariable=variable,             font=self.fonts["body"],             fg=COLORS["text"],             bg=COLORS["entry"],             relief="solid",             bd=1,         ).grid(row=row, column=column + 1, sticky="ew", padx=(0, 18), pady=6)      def make_button(self, parent: tk.Misc, text: str, command, compact: bool = False) -> tk.Button:         button = tk.Button(             parent,             text=text,             command=command,             font=self.fonts["button"],             fg="#FFFFFF",             bg=COLORS["accent"],             activeforeground="#FFFFFF",             activebackground=COLORS["accent_hover"],             relief="flat",             bd=0,             padx=14 if compact else 24,             pady=6 if compact else 10,             cursor="hand2",         )         return button      def link_label(self, parent: tk.Misc, text: str, url: str) -> tk.Label:         label = tk.Label(             parent,             text=text,             font=self.fonts["footer"],             fg=COLORS["footer"],             bg=COLORS["background"],             cursor="hand2",         )         label.bind("<Button-1>", lambda _event: webbrowser.open(url))         label.bind("<Enter>", lambda _event: label.configure(fg=COLORS["accent"]))         label.bind("<Leave>", lambda _event: label.configure(fg=COLORS["footer"]))         return label      def choose_save_folder(self) -> None:         initial_dir = self.save_folder_var.get().strip() or default_save_folder()         selected = filedialog.askdirectory(             title=UI_TEXT["dialog_select_save_dir"],             initialdir=initial_dir if os.path.isdir(initial_dir) else default_save_folder(),         )         if selected:             self.save_folder_var.set(selected)      def collect_request(self) -> PdfRequest | None:         start = parse_date_text(self.start_date_var.get())         if start is None:             messagebox.showerror(UI_TEXT["dialog_error_title"], UI_TEXT["error_start_date"])             return None          end = parse_date_text(self.end_date_var.get())         if end is None:             messagebox.showerror(UI_TEXT["dialog_error_title"], UI_TEXT["error_end_date"])             return None          if end < start:             messagebox.showerror(UI_TEXT["dialog_error_title"], UI_TEXT["error_date_order"])             return None          save_folder = self.save_folder_var.get().strip()         if not save_folder:             messagebox.showerror(UI_TEXT["dialog_error_title"], UI_TEXT["error_save_folder"])             return None          events: list[CalendarEvent] = []         completion_date: date | None = None         for row in self.event_rows:             key = str(row["key"])             date_var = row["date_var"]             content_var = row["content_var"]             assert isinstance(date_var, tk.StringVar)             assert isinstance(content_var, tk.StringVar)             raw_date = date_var.get().strip()             content = content_var.get().strip()             if not raw_date:                 continue             event_date = parse_date_text(raw_date)             if event_date is None:                 messagebox.showerror(                     UI_TEXT["dialog_error_title"],                     UI_TEXT["error_event_date"].format(content=content),                 )                 return None             if not (start <= event_date <= end):                 messagebox.showerror(                     UI_TEXT["dialog_error_title"],                     UI_TEXT["error_event_range"].format(content=content),                 )                 return None             if not content:                 default_label = next(                     str(item["label"]) for item in UI_TEXT["event_items"] if item["key"] == key                 )                 content = default_label             events.append(CalendarEvent(key=key, event_date=event_date, content=content))             if key == "completion":                 completion_date = event_date          return PdfRequest(             site_name=self.site_name_var.get().strip(),             branch_name=self.branch_name_var.get().strip(),             staff_name=self.staff_name_var.get().strip(),             phone=self.phone_var.get().strip(),             start_date=start,             end_date=end,             save_folder=save_folder,             events=tuple(events),             completion_date=completion_date,         )      def on_create_pdf(self) -> None:         if self.is_processing:             return         request = self.collect_request()         if request is None:             return          self.save_current_config()         self.is_processing = True         self.status_var.set(UI_TEXT["status_processing"])         self.create_button.configure(state="disabled", bg=COLORS["accent_disabled"])         self.progress.start(12)          worker = threading.Thread(target=self.worker_generate_pdf, args=(request,), daemon=True)         worker.start()         self.root.after(100, self.poll_worker)      def worker_generate_pdf(self, request: PdfRequest) -> None:         try:             output_path = generate_pdf(request)             self.result_queue.put(("ok", output_path))         except Exception as exc:             self.result_queue.put(("error", str(exc)))      def poll_worker(self) -> None:         try:             status, payload = self.result_queue.get_nowait()         except queue.Empty:             self.root.after(100, self.poll_worker)             return          self.progress.stop()         self.create_button.configure(state="normal", bg=COLORS["accent"])         self.is_processing = False          if status == "ok":             output_path = Path(payload)             self.status_var.set(UI_TEXT["status_saved"])             messagebox.showinfo(                 UI_TEXT["dialog_saved_title"],                 UI_TEXT["dialog_saved_message"].format(path=str(output_path)),             )             open_folder(str(output_path.parent))         else:             self.status_var.set(UI_TEXT["status_error"])             messagebox.showerror(UI_TEXT["dialog_error_title"], str(payload))      def save_current_config(self) -> None:         save_config(             {                 "staff_name": self.staff_name_var.get().strip(),                 "phone": self.phone_var.get().strip(),                 "branch_name": self.branch_name_var.get().strip(),                 "save_folder": self.save_folder_var.get().strip(),             }         )   def main() -> None:     set_windows_app_id()     root = tk.Tk()     WorkCalendarApp(root)     root.mainloop()   if __name__ == "__main__":     main()